```class Solution:
    def strongPasswordChecker(self, password: str) -> int:
        n = len(password)
        if n < 6:
            return 6 - n
        if n <= 20:
            has_lower = any(c.islower() for c in password)
            has_upper = any(c.isupper() for c in password)
            has_digit = any(c.isdigit() for c in password)
            has_three_repeat = any(password[i:i+3].count(c) >= 3 for i in range(n-2) for c in set(password[i:i+3]))
            missing = 0
            if not has_lower:
                missing += 1
            if not has_upper:
                missing += 1
            if not has_digit:
                missing += 1
            if has_three_repeat:
                missing += 1
            return max(missing, 3 - (n - 3) % 3)
        else:
            groups = []
            i = 0
            while i < n:
                c = password[i]
                j = i + 1
                while j < n and password[j] == c:
                    j += 1
                groups.append((c, j - i))
                i = j
            groups.sort(key=lambda x: x[1])
            dels = 0
            for i, (c, length) in enumerate(groups):
                if length >= 3:
                    dels += max(0, length - 3)
            dels += max(0, n - 20)
            return dels + max(3 - (n - 3) % 3, 0)
